<script setup lang="ts">
import Loading from "~/components/icons/Loading/index.vue";
import UploadCloud from "~/components/icons/UploadCloud/index.vue";

const props = defineProps({
  id: {
    type: String,
    default: "",
  },
  type: {
    type: String as () => "button" | "submit" | "reset" | undefined,
    default: "button",
  },
  disabled: {
    type: Boolean,
    default: false,
  },
  loading: {
    type: Boolean,
    default: false,
  },
  labelFor: {
    type: String,
    default: "",
  },
  hovered: {
    type: Boolean,
    default: false,
  },
  color: {
    type: String as () => "primary" | "success" | "info" | "warning" | "error",
    default: "primary",
  },
});

const emit = defineEmits(["on-click"]);

const buttonClass = computed((): string => {
  const baseClass =
    "py-2.5 px-3.5 text-sm font-[600] text-gray-700 stroke-gray-700 border rounded-lg flex items-center justify-center transition";
  const hoverClass =
    props.disabled || props.loading ? "" : "hover:bg-[#0000000a]";
  const fileHoverClass = props.hovered ? "bg-[#0000000a]" : "";
  const disabled = props.disabled ? "bg-gray-100 opacity-75" : "";
  const cursor =
    props.disabled || props.loading ? "cursor-not-allowed" : "cursor-pointer";
  return `${baseClass} ${disabled} ${cursor} ${hoverClass} ${fileHoverClass}`;
});

const variant = {
  primary: "stroke-primary-500 ",
  success: "stroke-success-500 ",
  info: "stroke-info-500 ",
  warning: "stroke-warning-500 ",
  error: "stroke-error-500 ",
};

const bgColor = computed(() => {
  return variant[props.color];
});
</script>

<template>
  <label
    :for="props.labelFor"
    :id="props.id"
    :type="type"
    :disabled="props.disabled"
    :class="buttonClass"
    @click="emit('on-click')"
  >
    <Loading
      v-if="props.loading"
      class="w-6 h-6 animate-spin text-gray-200 fill-gray-400"
    />

    <span v-else class="space-y-2 flex items-center flex-col">
      <div class="rounded-full bg-primary-50 bg-opacity-20 p-[6px] mb-auto">
        <div class="rounded-full bg-primary-50 bg-opacity-20 p-[8px]">
          <UploadCloud size="20" :class="bgColor" />
        </div>
      </div>
      <div v-if="props.hovered">Release to drop files here</div>
      <div v-else>
        Click to upload
        <span class="font-normal text-gray-500"> or drag and drop</span>
      </div>
      <span class="font-normal text-xs text-gray-500">Excel (max. 5MB)</span>
    </span>
  </label>
</template>

<style scoped></style>
